const org = 'OpenSIN-AI';
const token = $env.GITHUB_TOKEN || process.env.GITHUB_TOKEN;
const pageSize = 100;
const repos = [];
for (let page = 1; page <= 10; page++) {
  const res = await fetch(`https://api.github.com/orgs/${org}/repos?per_page=${pageSize}&page=${page}&type=all`, {
    headers: { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' }
  });
  const data = await res.json();
  if (!Array.isArray(data) || data.length === 0) break;
  repos.push(...data.map(r => ({ owner: org, repo: r.name, full_name: r.full_name })));
  if (data.length < pageSize) break;
}
return [{ json: { repos, total: repos.length } }];

const repos = $input.first().json.repos;
const governance = [
  { path: 'governance/repo-governance.json', source: 'template' },
  { path: 'n8n-workflows/inbound-intake.json', source: 'template' },
  { path: 'scripts/watch-pr-feedback.sh', source: 'template' },
  { path: 'docs/03_ops/inbound-intake.md', source: 'template' },
  { path: 'platforms/registry.json', source: 'template' }
];
const items = [];
for (const repo of repos) {
  for (const g of governance) {
    items.push({ json: { ...repo, governance_path: g.path, source: g.source } });
  }
}
return items;

const item = $input.first().json;
const existing = $input.all().find(i => i.json.existing === true);
if (existing) {
  return [{ json: { ...item, action: 'skip', reason: 'already_exists' } }];
}
return [{ json: { ...item, action: 'apply' } }];
